import{_ as a,o,c as t,a3 as m}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"20. Full Time Employment","description":"","frontmatter":{"title":"20. Full Time Employment","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","employment","classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/employment-types/20-full-time-employment.md","filePath":"ebas/has-managers-admin/common-terms/employment-types/20-full-time-employment.md"}'),n={name:"ebas/has-managers-admin/common-terms/employment-types/20-full-time-employment.md"};function r(l,e,s,i,p,c){return o(),t("div",null,[...e[0]||(e[0]=[m('<h1 id="_20-full-time-employment" tabindex="-1">20. Full Time Employment <a class="header-anchor" href="#_20-full-time-employment" aria-label="Permalink to &quot;20. Full Time Employment&quot;">​</a></h1><p><strong>20.1</strong> A full-time Employee is one who is ready, willing and available to work a full week of 38 hours, or an average of 38 hours as per <a href="/eba/ebas/has-managers-admin/common-terms/employment-types/22-part-time-review-of-hours.html">clause 22</a> of Section 2 and <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/7-commencement-date-and-period-of-operation.html">clause 7</a> of Section 3 (Hours of Work) at the times and during the hours that are mutually agreed upon, or in the absence of such agreement, as prescribed by the Employer.</p><p><strong>20.2</strong> Subject to the provisions of <a href="/eba/ebas/has-managers-admin/common-terms/employment-types/22-part-time-review-of-hours.html">clause 22</a> of Section 2 and <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/7-commencement-date-and-period-of-operation.html">clause 7</a> of Section 3 (Hours of Work) a full-time Employee will be paid the full weekly wage for their classification irrespective of the number of hours worked not exceeding 38, or an average of 38 per week.</p><p>Plain language terms: full-time, FT.</p>',4)])])}const h=a(n,[["render",r]]);export{u as __pageData,h as default};
